import React, { useState } from "react";

interface Slot {
  id: number;
  isAvailable: boolean;
  isSelected: boolean;
}

const SlotDiagram = () => {
  // Sample slots data: Initially, some slots are occupied (false) and others are available (true)
  const [slots, setSlots] = useState<Slot[]>([
    { id: 1, isAvailable: true, isSelected: false },
    { id: 2, isAvailable: false, isSelected: false },
    { id: 3, isAvailable: true, isSelected: false },
    { id: 4, isAvailable: true, isSelected: false },
    { id: 5, isAvailable: false, isSelected: false },
    { id: 6, isAvailable: true, isSelected: false },
  ]);

  // Handle slot selection
  const handleSlotClick = (id: number) => {
    setSlots((prevSlots) =>
      prevSlots.map((slot) =>
        slot.id === id && slot.isAvailable
          ? { ...slot, isSelected: !slot.isSelected }
          : slot
      )
    );
  };

  return (
    <div>
      <h2 className="text-xl font-semibold mb-4">Select a Parking Slot</h2>
      <div className="grid grid-cols-3 gap-4">
        {slots.map((slot) => (
          <div
            key={slot.id}
            onClick={() => handleSlotClick(slot.id)}
            className={`p-6 text-center rounded-md cursor-pointer ${
              !slot.isAvailable
                ? "bg-gray-400 text-white point"
                : slot.isSelected
                ? "bg-blue-400 text-white"
                : "bg-green-700 text-white"
            }`}
          >
            {`Slot ${slot.id}`}
          </div>
        ))}
      </div>
    </div>
  );
};

const SlotSelection = () => {
  const [selectedSlot, setSelectedSlot] = useState<string>("");
  const slots = [
    "Slot 1",
    "Slot 2",
    "Slot 3",
    "Slot 4",
    "Slot 5",
    "Slot 6",
    "Slot 7",
    "Slot 8",
    "Slot 9",
    "Slot 10",
    "Slot 11",
    "Slot 12",
    "Slot 13",
    "Slot 14",
    "Slot 15",
  ];

  const handleSlotChange = (e: React.ChangeEvent<HTMLSelectElement>) => {
    setSelectedSlot(e.target.value);
  };

  return (
    <div className="p-4 border-2 border-gray-300 rounded-lg">
      <h2 className="text-xl font-semibold mb-4">Select a Parking Slot</h2>
      <div>
        <select
          value={selectedSlot}
          onChange={handleSlotChange}
          className="w-full p-2 border border-gray-300 rounded-md"
        >
          <option value="">Select Slot</option>
          {slots.map((slot, index) => (
            <option key={index} value={slot}>
              {slot}
            </option>
          ))}
        </select>
      </div>
      <SlotDiagram />
    </div>
  );
};

export default SlotSelection;
